  ('medical-tech-moex-00482', 'medical-tech', 'medical-tech-moex-111-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '造成支氣管擴張症（bronchiectasis）之敘述，下列何者錯誤？', '["腫瘤、異物、痰液阻塞會造成支氣管擴張", "原發性纖毛運動困難（primary ciliary dyskinesia）是一種遺傳疾病，會導致纖毛構造異常", "囊性纖維化（cystic fibrosis）是後天細菌感染造成，引起細胞膜上氯離子通道缺損", "結核菌、病毒、黴菌感染，都有可能造成支氣管壁的破壞與擴張"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:30+00:00", "source_pdf_sha1": "384ade0841a0", "answer_pdf_sha1": "b2f5551a1ec8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111020", "c": "308", "s": "11", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "111", "exam_name": "111年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 63, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
