  ('medical-tech-moex-00486', 'medical-tech', 'medical-tech-moex-111-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '有關庫欣氏症候群（Cushing syndrome）之敘述，下列何者錯誤？', '["如因庫欣氏病（Cushing disease）所引起的，血液中促腎上腺皮質素（adrenocorticotrophic hormone, ACTH） 值會下降", "如因腎上腺腺瘤（adrenocortical adenoma）所引起的，血液中促腎上腺皮質素（adrenocorticotrophic hormone, ACTH）值會下降", "肺小細胞癌（small cell carcinoma）可引起此一症候群", "長期服用類固醇（steroid）藥物是臨床上造成此一症候群最常見的原因"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:30+00:00", "source_pdf_sha1": "384ade0841a0", "answer_pdf_sha1": "b2f5551a1ec8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111020", "c": "308", "s": "11", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "111", "exam_name": "111年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 67, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
